// ── Full FL ZIP list (loaded lazily from ACS data embedded below) ─────────────
// 1013 FL ZCTAs from Census ACS 5-year 2022
// Format: [zip, population, median_hhi]
const FL_ZIPS_RAW = require('./flZipData.json');

// ── Centroid cache (persisted to disk) ────────────────────────────────────────
let _centroidCache = null;

function loadCentroidCache() {
  if (_centroidCache) return _centroidCache;
  try {
    _centroidCache = JSON.parse(fs.readFileSync(CENTROID_CACHE, 'utf8'));
  } catch (_) {
    _centroidCache = {};
  }
  return _centroidCache;
}

function saveCentroidCache() {
  if (!_centroidCache) return;
  try {
    const tmp = CENTROID_CACHE + '.tmp';
    fs.writeFileSync(tmp, JSON.stringify(_centroidCache));
    fs.renameSync(tmp, CENTROID_CACHE);
  } catch (_) {}
}

// ── Nominatim centroid resolver ───────────────────────────────────────────────
async function resolveZipCentroid(zip) {
  const cache = loadCentroidCache();
  if (cache[zip]) return cache[zip];
  if (SEED_CENTROIDS[zip]) {
    cache[zip] = SEED_CENTROIDS[zip];
    return SEED_CENTROIDS[zip];
  }

  return new Promise((resolve) => {
    const url = `https://nominatim.openstreetmap.org/search?postalcode=${zip}&country=US&format=json&limit=1`;
    const req = https.get(url, {
      headers: { 'User-Agent': 'LocalIntel-ZipRegistry/1.0 (localintel@mcflamingo.com)' }
    }, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const results = JSON.parse(data);
          if (results.length > 0) {
            const lat = parseFloat(results[0].lat);
            const lon = parseFloat(results[0].lon);
            cache[zip] = [lat, lon];
            saveCentroidCache();
            resolve([lat, lon]);
          } else {
            resolve(null);
          }
        } catch (_) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(8000, () => { req.destroy(); resolve(null); });
  });
}

// ── Bounding box from centroid ────────────────────────────────────────────────
// deg=0.07 ≈ 5-mile radius for dense urban; 0.12 for rural
function bboxFromCentroid(lat, lon, deg = 0.07) {
  return {
    minLat: lat - deg,
    maxLat: lat + deg,
    minLon: lon - deg,
    maxLon: lon + deg,
  };
}

// ── Public API ────────────────────────────────────────────────────────────────

function getAllZips() {
  return FL_ZIPS_RAW.map(r => ({
    zip:         r.zip,
    population:  r.population,
    median_hhi:  r.median_hhi,
    lat:         SEED_CENTROIDS[r.zip]?.[0] ?? null,
    lon:         SEED_CENTROIDS[r.zip]?.[1] ?? null,
  }));
}

function getZip(zip) {
  const r = FL_ZIPS_RAW.find(z => z.zip === zip);
  if (!r) return null;
  const cache = loadCentroidCache();
  const coords = SEED_CENTROIDS[zip] || cache[zip] || null;
  return {
    zip:        r.zip,
    population: r.population,
    median_hhi: r.median_hhi,
    lat:        coords?.[0] ?? null,
    lon:        coords?.[1] ?? null,
  };
}

async function getZipBbox(zip, deg = 0.07) {
  let coords = SEED_CENTROIDS[zip] || loadCentroidCache()[zip];
  if (!coords) coords = await resolveZipCentroid(zip);
  if (!coords) return null;
  return bboxFromCentroid(coords[0], coords[1], deg);
}

// Priority queue: sort by population desc for worker ordering
function getZipsByPriority() {
  return FL_ZIPS_RAW
    .slice()
    .sort((a, b) => (b.population || 0) - (a.population || 0));
}

module.exports = { getAllZips, getZip, getZipBbox, getZipsByPriority, resolveZipCentroid, bboxFromCentroid };
